// Worked focus: cmem-integer-promotions-conversions — Trace integer promotions and usual arithmetic conversions before comparing, shifting, indexing, or sizing.
/* Evidence: cmem-worked-cmem-values-integers-overflow-5 */
/* Browser practice: PicoC 3.2.2 C89/C90 plus selected C99. */
/* Changed case 5504; native C23 claims require explicit transfer gates. */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>


static int worked_cmem_values_integers_overflow_5(size_t count, size_t width, size_t limit, size_t *bytes) {
  if (bytes == NULL || width == 0) return 0;
  if (count > limit / width) return 0;
  *bytes = count * width;
  return 1;
}

int main(void) {
  size_t bytes = 99;
  int rejected = worked_cmem_values_integers_overflow_5((size_t)26, (size_t)8, (size_t)64, &bytes);
  int accepted = worked_cmem_values_integers_overflow_5((size_t)6, (size_t)4, (size_t)64, &bytes);
  int invariant = !rejected && accepted && bytes == (size_t)24;
  printf("size bytes=%lu invariant=%d\n", (unsigned long)bytes, invariant);
  return invariant ? 0 : 1;
}

